def reverse_string(s):
    """Return the reverse of the input string without using reversed() or slicing."""
    reversed_chars = []
    for char in s:
        # Insert each new character at the beginning of the list
        reversed_chars.insert(0, char)
    # Join the list back into a string
    return ''.join(reversed_chars)

